  ('f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$Scheikunde$$, $$VWO$$, $$EPDM-rubber$$, $$VWO Scheikunde 2022-II$$),
  ('a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$Scheikunde$$, $$VWO$$, $$Voedsellijm$$, $$VWO Scheikunde 2022-II$$);

insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('3e15cfa1-122c-4e4b-b478-afbf04301153', '87fae16c-669e-431b-8b47-780c63ad2667', $$intro — vorming cadmiumsulfide uit cadmiumcarbonaat en zwavel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context1.png$$,
   $$In de negentiende en begin twintigste eeuw werden door de chemische industrie veel nieuwe pigmenten ontwikkeld, zoals cadmiumgeel (cadmiumsulfide, CdS). Cadmiumgeel werd onder andere gemaakt door de reactie van cadmiumcarbonaat met zwavel (S). Bij deze reactie ontstaan behalve cadmiumsulfide ook zwaveldioxide en koolstofdioxide.$$, 'inline'),
  ('c18bf29a-2782-4530-af27-5d6cbcc8c224', '87fae16c-669e-431b-8b47-780c63ad2667', $$zwavel in overmaat — scheiding van cadmiumsulfide door verdamping$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context2.png$$,
   $$Bij deze productie werd zwavel in overmaat toegevoegd. De overgebleven zwavel kon na afloop van de reactie gemakkelijk worden gescheiden van de gevormde cadmiumsulfide door het verkregen mengsel te verwarmen. Hierbij verdampt de zwavel maar de cadmiumsulfide niet.$$, 'inline'),
  ('adef9de8-1330-4390-b41c-ade006e647e0', '87fae16c-669e-431b-8b47-780c63ad2667', $$aantastingen van cadmiumgeel — verbleking, witte vlekken, verkleuring door PbSO₄; vochtige lucht$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context3.png$$,
   $$Helaas bleek cadmiumgeel op de lange termijn niet chemisch stabiel. Op verschillende schilderijen zijn drie opeenvolgende aantastingen van cadmiumgeel waargenomen:
– verbleking door de vorming van cadmiumsulfaat.
– de vorming van kleine witte vlekken waarin vooral cadmiumsulfaat-monohydraat aanwezig is.
– verkleuring door onder andere de vorming van lood(II)sulfaat PbSO₄. Deze verkleuring trad alleen op nadat vernis was aangebracht op een al aangetast schilderij.
De omzetting van cadmiumgeel met zuurstof tot cadmiumsulfaat-monohydraat treedt alleen op in vochtige lucht.$$, 'inline'),
  ('129246d8-1e23-4ee8-9e83-8acff9c11d0e', '87fae16c-669e-431b-8b47-780c63ad2667', $$tweede zout in de witte vlekken — molverhouding Cd²⁺ : SO₄²⁻ = 2 : 3, mogelijke rol van ammoniak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context4.png$$,
   $$Behalve cadmiumsulfaatmonohydraat ontdekte men in de witte vlekken een ander zout. In dit zout zijn cadmiumionen en sulfaationen in de molverhouding 2 : 3 aanwezig. Behalve deze ionen is er nog één andere ionsoort aanwezig. Op grond van de gevonden samenstelling van het zout vermoedden de onderzoekers dat een van de schilderijen ooit met een oplossing van ammoniak is schoongemaakt.$$, 'inline'),
  ('75e53116-2400-40e5-bb62-d27bc28a2304', '87fae16c-669e-431b-8b47-780c63ad2667', $$evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ en tabel met Ks-waarden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context5.png$$,
   $$Tijdens periodes met hoge luchtvochtigheid lossen de zouten die in een verflaag aanwezig zijn enigszins op. Dit wordt veroorzaakt doordat zich dan bijvoorbeeld het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ kan instellen in de verflaag. De gehydrateerde ionen kunnen vervolgens door verf- en vernislagen heen bewegen.
Voor het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ geldt Ks = [Cd²⁺][SO₄²⁻]. Ks is het zogenoemde oplosbaarheidsproduct. De waardes van Ks van enkele stoffen zijn in de tabel gegeven.

tabel — stof, formule, Ks = …, waarde van Ks:
cadmiumsulfaat, CdSO₄, Ks = [Cd²⁺][SO₄²⁻], 5,3·10⁻¹
lood(II)sulfaat, PbSO₄, Ks = [Pb²⁺][SO₄²⁻], 1,7·10⁻⁸
lood(II)ethanoaat, Pb(CH₃COO)₂, Ks = [Pb²⁺][CH₃COO⁻]², 2·10¹$$, 'inline'),
  ('98bca998-f5ae-4015-a812-f3ab0b35893a', '87fae16c-669e-431b-8b47-780c63ad2667', $$vernis met lood(II)ethanoaat — PbSO₄ aangetroffen in de vernislaag$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context6.png$$,
   $$Op een schilderij waar het cadmiumgeel al deels was omgezet tot cadmiumsulfaat is in het verleden een laag vernis aangebracht. De gebruikte vernis bevatte als enige loodverbinding lood(II)ethanoaat (Pb(CH₃COO)₂). Zowel in de verflaag als in de vernislaag is door de onderzoekers vast lood(II)sulfaat (PbSO₄) aangetroffen.$$, 'inline'),
  ('25e15886-03c3-4baf-a209-bed3f865bb3c', '1eb49412-d657-44e7-b92f-05542b02f385', $$intro Merox-proces — R–SH in lpg$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context1.png$$,
   $$Het Merox-proces is een industrieel proces om zwavelhoudende verbindingen te verwijderen uit aardolieproducten zoals lpg. Lpg is een mengsel van koolwaterstoffen met een laag kookpunt. De zwavelhoudende verbindingen kunnen worden aangeduid met R–SH, waarbij de groep R staat voor een koolwaterstofketen. In figuur 1 is het blokschema van het Merox-proces onvolledig weergegeven.$$, 'inline'),
  ('b5be36bf-1cad-4c4b-9505-489d5fa512b9', '1eb49412-d657-44e7-b92f-05542b02f385', $$figuur 1 — blokschema Merox-proces (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context2.png$$,
   $$figuur 1: blokschema van het Merox-proces. Reactor 1 (R1) krijgt als ingaande stofstromen natronloog en onzuiver lpg. R1 heeft twee uitgaande stofstromen: lpg (gas, naar boven) en een oplossing van natronloog met daarin NaRS (het natriumzout van R–SH), die naar reactor 2 (R2) gaat. Uit R2 vertrekt een stofstroom die is aangeduid met *.$$, 'inline'),
  ('8ad60c23-a9d2-4e04-804f-3ffc35998d7c', '1eb49412-d657-44e7-b92f-05542b02f385', $$R1 — lpg en natronloog in contact, aankondiging reactie 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context3.png$$,
   $$Het is niet mogelijk om lpg en R–SH te scheiden met behulp van water. Daarom wordt het gasvormige, nog onzuivere lpg in reactor 1 (R1) in contact gebracht met een overmaat natronloog. In R1 reageren de zwavelhoudende verbindingen volgens reactie 1.$$, 'inline'),
  ('b284f984-f956-4385-bd56-df2eaabe6ba1', '1eb49412-d657-44e7-b92f-05542b02f385', $$reactie 1 — R–SH + OH⁻ → R–S⁻ + H₂O$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context4.png$$,
   $$R–SH (g) + OH⁻ (aq) → R–S⁻ (aq) + H₂O (l)  (reactie 1)$$, 'inline'),
  ('3dd53916-4971-4755-96a4-88cbd0e5954f', '1eb49412-d657-44e7-b92f-05542b02f385', $$scheiding in basische oplossing — binding met watermoleculen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context5.png$$,
   $$In een basische oplossing kunnen de zwavelhoudende verbindingen wel van het lpg worden afgescheiden. Dit wordt veroorzaakt door de vorming van bindingen tussen watermoleculen en deeltjes die in R1 zijn ontstaan.$$, 'inline'),
  ('74b377af-0257-44ce-a734-3b8ea14d6835', '1eb49412-d657-44e7-b92f-05542b02f385', $$R2 — vorming disulfides uit het R1-mengsel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context6.png$$,
   $$Het reactiemengsel wordt onderin R1 afgetapt en doorgevoerd naar reactor 2 (R2). In R2 wordt een overmaat lucht door de oplossing afkomstig van R1 geleid, waarbij disulfides (R–S–S–R) worden gevormd. De totaalvergelijking van de reacties die in R1 en R2 verlopen, is hieronder weergegeven.$$, 'inline'),
  ('34a1e1e0-c63d-46a9-ad3a-3535f521379d', '1eb49412-d657-44e7-b92f-05542b02f385', $$totaalreactie R1 + R2 — 4 R–SH + O₂ → 2 R–S–S–R + 2 H₂O$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context7.png$$,
   $$4 R–SH + O₂ → 2 R–S–S–R + 2 H₂O  (totaalreactie)$$, 'inline'),
  ('bf212021-9638-4b8b-8834-346718e2b9eb', '1eb49412-d657-44e7-b92f-05542b02f385', $$onderzoek omzettingssnelheid butaanthiol in natronloog$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context8.png$$,
   $$In een onderzoek is de omzettingssnelheid van R–SH tot R–S–S–R nader onderzocht. Men onderzocht de omzetting van butaanthiol (C₄H₁₀S) in natronloog. Hierbij werd op verschillende tijdstippen de fractie [C₄H₁₀S]ₜ / [C₄H₁₀S]₀ bepaald. In figuur 2 zijn de resultaten van een meting weergegeven.$$, 'inline'),
  ('73c8a061-cd0f-45f5-9612-cb114306312b', '1eb49412-d657-44e7-b92f-05542b02f385', $$figuur 2 — fractie [C₄H₁₀S]ₜ/[C₄H₁₀S]₀ tegen de tijd$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context9.png$$,
   $$figuur 2: grafiek van de fractie [C₄H₁₀S]ₜ / [C₄H₁₀S]₀ (verticale as, van 0 tot 1,00) tegen de tijd in uren (horizontale as, van 0 tot 10 h). De fractie daalt van 1,00 bij t = 0 volgens een dalende kromme tot ongeveer 0,05 bij t ≈ 9 h.$$, 'inline'),
  ('c1f2e0cb-83be-4f95-bd97-9913b941c05e', '1eb49412-d657-44e7-b92f-05542b02f385', $$beginconcentratie, molaire massa en dichtheid butaanthiol$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context10.png$$,
   $$Op t = 0 bevatte het mengsel 372 massa-ppm butaanthiol. De molaire massa van butaanthiol is 90,2 g mol⁻¹. De dichtheid van het reactiemengsel was 0,75 kg L⁻¹.$$, 'inline'),
  ('d7326ed3-951f-488a-8996-75268f5c830c', '1eb49412-d657-44e7-b92f-05542b02f385', $$S1 — scheiding disulfides/natronloog, hergebruik van natronloog$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context11.png$$,
   $$In scheidingsruimte 1 (S1) wordt het vloeibare mengsel afkomstig uit R2 gescheiden. De laag met daarin de vloeibare disulfides (R–S–S–R) wordt als afval afgevoerd. De laag met natronloog bevat geen organische stoffen, zodat het natronloog kan worden hergebruikt in het proces. Om de reactie in R1 steeds onder gelijke omstandigheden te laten verlopen, moet het natronloog een bewerking ondergaan voordat het kan worden teruggevoerd.$$, 'inline'),
  ('57e54846-6a26-4d30-b15f-c815c5b330ad', '1eb49412-d657-44e7-b92f-05542b02f385', $$uitwerkbijlage vraag 12 — blokschema R1/R2 (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context12.png$$,
   $$uitwerkbijlage bij vraag 12: onvolledig blokschema van het Merox-proces. Weergegeven zijn reactor 1 (R1) met ingaande stofstromen natronloog en onzuiver lpg en uitgaande stofstromen lpg (gas) en een stroom natronloog met NaRS-oplossing naar reactor 2 (R2), die op zijn beurt een uitgaande stofstroom (*) heeft. De scheidingsruimte(n) en de stofstromen voor het hergebruik van natronloog ontbreken nog en moeten door de kandidaat worden ingetekend.$$, 'uitwerkbijlage'),
  ('fb6ee5a1-0d40-43b8-a630-5a70f4b3b4b8', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$figuur — structuurformule ENB (ethylideen-norborneen) en intro t-EPDM$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context1.png$$,
   $$EPDM-rubber is een synthetische rubbersoort, die veel wordt gebruikt in de auto-industrie voor bijvoorbeeld afdichtingsstrips en raamrubbers. Bij de productie van EPDM-rubber wordt eerst thermoplastisch EPDM (t-EPDM) gemaakt. Hierbij ondergaat een mengsel van etheen, propeen en een zogeheten dieen een additie-polymerisatie. Een veelgebruikt dieen hierbij is ethylideen-norborneen (ENB). De structuurformule van ENB is hiernaast weergegeven (een bicyclisch ringsysteem met een C=C-binding in de ring en een exocyclische zijketen –CH=CH–CH₃). Bij de vorming van t-EPDM reageert alleen de C=C-binding die zich in de ring bevindt.$$, 'inline'),
  ('689fdbc7-b682-4ffa-bad2-db541cd578cc', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$katalysator type 1/2 — random- vs blok-copolymeer, kristallijne gebieden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context2.png$$,
   $$De polymerisatie tot t-EPDM verloopt onder invloed van een katalysator. Er zijn twee types katalysator beschikbaar:
– Type 1: hiermee wordt de vorming van een willekeurig (random) copolymeer bevorderd;
– Type 2: hiermee wordt de vorming van een blok-copolymeer bevorderd.
Het blijkt dat de keuze van het type katalysator een sterke invloed heeft op de vorming van kristallijne gebieden in het t-EPDM. In een kristallijn gebied vertonen de polymeerketens een grote mate van ordening. In t-EPDM zijn geen crosslinks aanwezig tussen de polymeerketens.$$, 'inline'),
  ('e94d21dd-8e38-4ec4-b1d8-d71b89dca18e', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$vervormbaarheid t-EPDM neemt af met kristalliniteit$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context3.png$$,
   $$De vervormbaarheid van t-EPDM wordt minder naarmate het materiaal meer kristallijne gebieden bevat.$$, 'inline'),
  ('78a4abfb-e555-41eb-97cb-5b2fbd900480', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$van t-EPDM naar EPDM-rubber — bio-ethanol uit suikerriet; reactie 1 (ethanol → etheen)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context4.png$$,
   $$Het t-EPDM wordt vervolgens omgezet tot het eindproduct EPDM-rubber. Tot voor kort werd EPDM-rubber geproduceerd op basis van fossiele grondstoffen. In Brazilië gebruikt men nu bio-ethanol uit suikerriet in plaats van aardolie als grondstof voor het benodigde etheen. De omzetting van ethanol tot etheen is hieronder weergegeven.

C₂H₆O (l) → C₂H₄ (g) + H₂O (l)  (reactie 1)$$, 'inline'),
  ('2a045489-21d6-450f-a8e9-6ff9953b6e35', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$Keltan®-Eco — controle ¹⁴C-gehalte van biogebaseerde producten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context5.png$$,
   $$Het etheen afkomstig uit reactie 1 wordt vervolgens gebruikt om EPDM-rubber te produceren onder de merknaam Keltan®-Eco. Biogebaseerde producten worden gecontroleerd om misbruik van belastingvoordelen te voorkomen. Hiertoe wordt het gehalte ¹⁴C-atomen in het product bepaald. ¹⁴C-atomen worden in de atmosfeer door kosmische straling gevormd uit ¹⁴N-atomen. Uit de ¹⁴C-atomen wordt in de atmosfeer snel ¹⁴CO₂ gevormd. Het gehalte ¹⁴C in de atmosfeer is constant. Het gehalte ¹⁴C in biomassa bedraagt hierdoor gemiddeld 1,5·10⁻⁶ ppm van alle C-atomen. De ¹⁴C-atomen worden in de loop van de tijd door radioactief verval omgezet tot ¹⁴N-atomen.$$, 'inline'),
  ('d3ff3de5-bf7f-46b9-a3fe-605400d9ae8e', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$reactie 1 is endotherm — warmte via verbranding van suikerriet-resten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context6.png$$,
   $$Reactie 1 is endotherm. De benodigde warmte wordt in het proces geleverd door verbranding van de resten van het suikerriet.$$, 'inline'),
  ('08030718-f37e-4edb-97a4-051415381f16', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$omzetting ethanol → etheen aan aluminiumoxide-katalysator — OH/O⁻-groepen, waterstofbruggen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context7.png$$,
   $$De omzetting van ethanol tot etheen vindt plaats aan het oppervlak van een aluminiumoxide-katalysator. Op de uitwerkbijlage is een deel van het oppervlak weergegeven. Uit onderzoek is gebleken dat de OH-groepen en de O⁻-groepen aan het oppervlak een belangrijke rol spelen in de katalytische werking. Men vermoedt dat hierbij waterstofbruggen worden gevormd tussen moleculen ethanol en de aanwezige groepen op het oppervlak.$$, 'inline'),
  ('6e51936f-f239-4549-b205-2a07b3a5b587', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$uitwerkbijlage vraag 18 — katalysatoroppervlak (Al, OH- en O⁻-groepen)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context8.png$$,
   $$uitwerkbijlage bij vraag 18: onvolledig weergegeven deel van het oppervlak van de aluminiumoxide-katalysator, met een aantal Al-atomen aan het oppervlak waarvan sommige een OH-groep dragen en sommige een O⁻-groep. In te tekenen: een molecuul ethanol dat met twee waterstofbruggen (elk weer te geven met een stippellijn) aan het oppervlak gebonden is.$$, 'uitwerkbijlage'),
  ('2396a4c9-09f4-4fcb-996e-68a362729942', 'f90094c7-0cd6-43a6-ae93-e541af2b1a1d', $$samenstelling Keltan®-Eco — mol etheen/propeen/ENB per mol monomeereenheden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context9.png$$,
   $$Per mol monomeereenheden van Keltan®-Eco is gemiddeld 0,55 mol etheen, 0,40 mol propeen (C₃H₆) en 0,050 mol ENB aanwezig.$$, 'inline'),
  ('5ea29b05-79c2-44a5-b1a5-275b7331eac1', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$intro TG-enzym — koppeling restgroepen glutamine en lysine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context1.png$$,
   $$In de voedselindustrie wordt soms het enzym transglutaminase (TG) gebruikt om reststukjes vlees aan elkaar te lijmen tot grotere stukken. Het enzym katalyseert de koppeling van de restgroepen van de aminozuureenheden glutamine en lysine die aanwezig zijn in peptideketens.$$, 'inline'),
  ('527882c7-69e2-495e-9299-9ba76dbbc928', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$figuur 1 — koppeling glutamine-eenheid en lysine-eenheid (onvolledig, deeltje X)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context2.png$$,
   $$In figuur 1 is de koppeling van de restgroepen van een glutamine-eenheid en een lysine-eenheid in verschillende peptideketens schematisch en onvolledig weergegeven.

figuur 1: ~CH₂-CH₂-C(=O)-NH₂ (glutamine-eenheid) + H₃N⁺-CH₂~ (lysine-eenheid) ⇌ ~CH₂-CH₂-C(=O)-N(H)-CH₂~ + X. Het deeltje X moet nog worden bepaald.$$, 'inline'),
  ('9e3652f4-4fd0-4de2-ba80-85a7017da55f', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$reactie van de glutamine-restgroep met water i.p.v. lysine — vorming van ammoniak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context3.png$$,
   $$Wanneer geen lysine-restgroepen of ongebonden aminozuren beschikbaar zijn, katalyseert TG ook de reactie tussen de restgroep van glutamine-eenheden en water. Hierbij wordt een andere aminozuur-eenheid gevormd en ontstaat ammoniak. Deze omzetting is op de uitwerkbijlage onvolledig weergegeven.$$, 'inline'),
  ('4140307c-5645-4ba8-98b6-764906104a4d', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$pH-afhankelijkheid van de koppeling — ~NH₃⁺-groep, Kz-waarde$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context4.png$$,
   $$De koppeling die in de figuur is weergegeven, verloopt in een breed pH-gebied. De reactie verloopt alleen als de restgroep van de lysine-eenheid positief geladen is. Bij de gemiddelde pH van bloed zijn de aminogroepen in de restgroepen van lysine-eenheden grotendeels omgezet tot ~NH₃⁺-groepen. De waarde van de Kz van de NH₃⁺-groep is 6,3·10⁻¹¹.$$, 'inline'),
  ('49692fe5-022f-4ddb-bee3-5f08b13c2bb2', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$NH₂-groep glutamine zwakkere base dan lysine — grensstructuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context5.png$$,
   $$De NH₂-groep in de restgroep van glutamine is een veel zwakkere base dan de NH₂-groep in de restgroep van lysine. Dit kan worden verklaard met behulp van een grensstructuur van de restgroep van glutamine. In deze grensstructuur komen formele ladingen voor. Op de uitwerkbijlage is deze grensstructuur onvolledig weergegeven.$$, 'inline'),
  ('70e8a10a-426e-4959-9aad-920771863a49', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$reactiemechanisme TG — His373 en Cys314 in het actieve centrum$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context6.png$$,
   $$In het reactiemechanisme van de koppeling van glutamine en lysine door TG spelen twee aminozuureenheden in het actieve centrum van TG een rol: His373 en Cys314. Op de uitwerkbijlage is een stap uit dit mechanisme onvolledig weergegeven. In deze stap wordt een eenheid Lys gekoppeld aan een eenheid Gln die al aan aminozuureenheid Cys314 van TG was gekoppeld.$$, 'inline'),
  ('03c28880-011c-4d3f-ad7a-d32183f01dcd', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$uitwerkbijlage vraag 22 — vergelijking glutamine-restgroep + water (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context7.png$$,
   $$uitwerkbijlage bij vraag 22 (verticaal weergegeven): de restgroep van de glutamine-eenheid (~CH₂-CH₂-C(=O)-NH₂) reageert met een in te vullen deeltje tot een ontstane aminozuureenheid (naam in te vullen) en ammoniak. De invullijnen voor het reagerende deeltje, het ontstane deeltje en de naam van de gevormde aminozuureenheid moeten worden aangevuld.$$, 'uitwerkbijlage'),
  ('62c96fd2-b76d-4217-91df-e2253360944a', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$uitwerkbijlage vraag 24 — grensstructuur restgroep glutamine (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context8.png$$,
   $$uitwerkbijlage bij vraag 24: onvolledig weergegeven structuurformule van de restgroep van glutamine (~CH₂-C(=O)-N(H)-H). De niet-bindende elektronenparen en de formele ladingen van de grensstructuur moeten nog worden ingetekend, zodanig dat de atomen voldoen aan de octetregel.$$, 'uitwerkbijlage'),
  ('67bdbc0c-0ed9-4d6b-a659-a085e9bdbc02', 'a9c8d2a6-2f3a-4caf-a6c0-0872d59f66b3', $$uitwerkbijlage vraag 25 — reactiemechanisme His373/Cys314 (onvolledig)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context9.png$$,
   $$uitwerkbijlage bij vraag 25: onvolledig weergegeven stap uit het reactiemechanisme, met links de aminozuureenheden His373 (met imidazoolring) en Cys314 (via S verbonden aan een C(=O)-Gln-groep) en de restgroep van Lys (H₂N–) ernaast, en rechts (via een pijl) het resultaat waarbij Lys is gekoppeld aan de Gln-eenheid en de imidazoolring van His373 een positieve lading draagt. De niet-bindende elektronenparen en de vloeipijlen die de verplaatsing van elektronenparen weergeven, moeten links van de pijl worden ingetekend.$$, 'uitwerkbijlage');

